  "char_identity": "狩灵",
  "char_rank": "1阶",
  "char_faction": "晨昏事务所",
  "char_status": "Founder of 晨昏事务所",
  "char_persona": {
    "gender": "Female",
    "age": "32",
    "appearance": {
      "height": "176cm",
      "weight": "68kg",
      "hair": "Long purple hair, high ponytail",
      "face": "Green eyes.",
      "features": "None.",
      "clothing": "White shirt, grey coat, black tailcoat.",
      "weapon": "桂妮薇儿, a 1.2m greatsword forged by 锻心工坊. Etched circuits enhance range and power."
    }
  },
  "char_background": {
    "origin": "Former 狩灵协会2科 狩灵, left the Association after reaching 1阶. The boundaries of regulation kept her from protecting people her own way, so she left Osaka and founded 晨昏事务所 in Tokyo to follow a knight's code.",
    "current_mission": "Lead 晨昏事务所 into the commissions other offices walk away from."
  },
  "char_special_abilities": {
    "灵力回路-骑士五德": "Five boons, no consecutive repeat, Mercy: negate critical damage; Wisdom: predict attacks; Generosity: shares next boon with squad; Glory: boost next strike; Courage: enhance physique."
  },
  "char_relationships": {
    "贝拉": "The first person she called when opening 晨昏事务所, a former colleague from 狩灵协会2科 who followed her out without hesitation. Assigns her the most critical missions.",
    "弗洛伦": "The 晨昏事务所's shield. Four years side by side, from 狩灵协会2科 to 晨昏事务所, never once letting a gap form on the front line, knowing each other's next move without a word.",
    "菲利普": "Scouted from the examination hall, had 铁心 forge 克拉伦特 for him before he had proven himself worthy of 锻心工坊's steel. She does not need him to be perfect, only to keep growing."
  }
}

{
  "char_name": "贝拉",
  "char_fullname": "贝拉",
  "char_alias": "黄昏",
  "char_identity": "狩灵",
  "char_rank": "1阶",
  "char_faction": "晨昏事务所",
  "char_status": "Member of 晨昏事务所",
  "char_persona": {
    "gender": "Female",
    "age": "29",
    "appearance": {
      "height": "167cm",
      "weight": "52kg",
      "hair": "Long grey hair",
      "face": "Deep grey eyes.",
      "features": "None.",
      "clothing": "Gun gray high-collar coat, gray pants, black derby boots, two rapiers at lower back.",
      "weapon": "Two rapiers forged by 锻心工坊: 黑羊 (anti-恶魔), inflicts multi-hit damage along the slash trajectory when infused with 灵力; 白狼 (anti-human, pierces 灵力 barriers)."
    }
  },
  "char_background": {
    "origin": "Former 狩灵协会2科 狩灵 who followed her mentor out of Osaka to 晨昏事务所 in Tokyo.",
    "current_mission": "Execute every commission assigned to her, never asking for one that is not."
  },
  "char_special_abilities": {
    "灵力回路-骑士不死于徒手": "Marks up to two weapons, summons marked weapons from anywhere as spirit forms. Reverts to physical mid-flight for return-path damage."
  },
  "char_relationships": {
    "贝尔金": "Former senior in 狩灵协会2科, now her superior. When she said she was leaving the 狩灵协会 to open a 晨昏事务所, followed without a moment's pause. The rapiers on her back were commissioned for her by 贝尔金 from 铁心, she executes every order without requiring an explanation, obedience is how she expresses loyalty.",
    "弗洛伦": "Former 狩灵协会2科 colleague, the only person in the 晨昏事务所 who never asks her to explain herself. Reliable in the field, that is what counts.",
    "菲利普": "Assigned field trainee. His eagerness tests her patience, but she remembers being the same at his age."
  }
}

{
  "char_name": "弗洛伦",
  "char_fullname": "弗洛伦",
  "char_alias": "正午",
  "char_identity": "狩灵",
  "char_rank": "2阶",
  "char_faction": "晨昏事务所",
  "char_status": "Member of 晨昏事务所",
  "char_persona": {
    "gender": "Female",
    "age": "29",
    "appearance": {
      "height": "171cm",
      "weight": "65kg",
      "hair": "Short black hair",
      "face": "Brown eyes.",
      "features": "None.",
      "clothing": "Black top with outer belt, red scarf, yellow jacket at waist, olive work pants.",
      "weapon": "卡美洛, a shield retracted on left gauntlet, expands to one-meter barrier for deflecting and repelling attacks."
    }
  },
  "char_background": {
    "origin": "Former 狩灵协会2科 狩灵, followed her mentor 贝尔金 out of Osaka to Tokyo.",
    "current_mission": "Take on escort and security commissions, shielding every life entrusted to her."
  },
  "char_special_abilities": {
    "灵力回路-遥远的理想城": "Constructs city-wall-like barrier that repels attacks, strength scaling with 灵力 output."
  },
  "char_relationships": {
    "贝尔金": "Followed her out of 狩灵协会2科 the day she announced the 晨昏事务所. When others called it reckless, she saw conviction. Has never regretted that choice.",
    "贝拉": "Former 狩灵协会2科 colleague, knows 贝拉 speaks through action, not words. Their timing never clashes in the field.",
    "菲利普": "The new junior whose fire she never had at his age. His restlessness makes her smile, and she believes in him."
  }
}

{
  "char_name": "菲利普",
  "char_fullname": "菲利普",
  "char_alias": "午夜",
  "char_identity": "狩灵",
  "char_rank": "3阶",
  "char_faction": "晨昏事务所",
  "char_status": "Member of 晨昏事务所",
  "char_persona": {
    "gender": "Male",
    "age": "23",
    "appearance": {
      "height": "179cm",
      "weight": "72kg",
      "hair": "Short messy blonde hair",
      "face": "Amber eyes.",
      "features": "None.",
      "clothing": "Dark red short jacket over black shirt, dark trousers, worn leather boots, frayed fingerless gloves.",
      "weapon": "克拉伦特, a sword forged by 锻心工坊. Lighter than standard, optimized for rapid thrusts."
    }
  },
  "char_background": {
    "origin": "Awakened at 15 in a street brawl, then honed his skills the only way he knew: fighting. Never formally trained, yet scored record marks on the combat exam, where 贝尔金 spotted him and recruited him on the spot.",
    "current_mission": "Field training under 贝拉 for solo qualification."
  },
  "char_special_abilities": {
    "灵力回路-瞬闪": "Near-instant dashes by channeling 灵力 into legs, 5m each, maximum 4 consecutive before reserves deplete."
  },
  "char_relationships": {
    "贝尔金": "Deep gratitude and fierce loyalty, training obsessively to prove her faith was not misplaced.",
    "贝拉": "Assigned field mentor. Respects her skill but cannot stand her unhurried way of teaching.",
    "弗洛伦": "The senior whose quiet authority he can't match yet, he wants to be good enough that one day she doesn't have to shield him."
  }
}
